#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

CI MAXN=1e3+5;
int n,m,d[MAXN],vis[MAXN],ans;
vector<PII> g[MAXN];
queue<int> q;
signed main(void)
{
    n=read(),m=read();
    FOR(i,1,m)
    {
        int u=read(),v=read(),w=read(),c=read();
        g[u].pb(mk(v,w*1001+c));
        g[v].pb(mk(u,w*1001+c));
    }
    ans=0;
    FOR(v,1,1000)
    {
        FOR(i,1,n)
		{
			d[i]=inf,vis[i]=0;
		}
        d[1]=0,vis[1]=1;
        q.push(1);
        wh(q.size())
        {
            int u=q.front();
			q.pop();
            vis[u]=0;
            FOI(e,g[u])
            {
                int to=e.fst,w=e.snd/1001,c=e.snd%1001;
                if(c<v)continue;
                if(d[u]+w<d[to])
                {
                    d[to]=d[u]+w;
                    if(!vis[to])
                    {
                        vis[to]=1;
                        q.push(to);
                    }
                }
            }
        }
        if(d[n]<inf/2)ans=max(ans,v*1000000/d[n]);
    }
    write(ans);
    return false;
}
